"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[13],{3183(t,e,a){a.r(e),a.d(e,{comp:()=>i,data:()=>o});var n=a(641);const r={},i=(0,a(6262).A)(r,[["render",function(t,e){return(0,n.uX)(),(0,n.CE)("div",null,[...e[0]||(e[0]=[(0,n.Fv)('<h1 id="gamification" tabindex="-1"><a class="header-anchor" href="#gamification"><span>Gamification</span></a></h1><p>Points, badges, leaderboards, and achievements — keeps bidders coming back beyond winning a lot.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-settings-gamification.png" alt="Settings → Gamification — points, leaderboard and badge configuration that drives the customer-facing gamification surface"></p><h2 id="components" tabindex="-1"><a class="header-anchor" href="#components"><span>Components</span></a></h2><table><thead><tr><th>Component</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Points</strong></td><td>Earned per bid / win / review; spent on rewards</td></tr><tr><td><strong>Badges</strong></td><td>One-time achievements (first bid, 10 wins, etc.)</td></tr><tr><td><strong>Leaderboard</strong></td><td>Public ranking by points / wins / spend</td></tr><tr><td><strong>Achievements</strong></td><td>Multi-step quests with progress bars</td></tr><tr><td><strong>Daily streaks</strong></td><td>Bonus for bidding multiple consecutive days</td></tr></tbody></table><h2 id="points" tabindex="-1"><a class="header-anchor" href="#points"><span>Points</span></a></h2><table><thead><tr><th>Action</th><th>Points (default)</th></tr></thead><tbody><tr><td>Bid placed</td><td><code>wkafw_points_per_bid</code> (default 1)</td></tr><tr><td>Auction won</td><td><code>wkafw_points_per_win</code> (default 10)</td></tr><tr><td>Review left</td><td><code>wkafw_points_per_review</code> (default 5)</td></tr><tr><td>Daily login</td><td>(configurable)</td></tr><tr><td>Refer a friend</td><td>(configurable)</td></tr></tbody></table><p>Each customer&#39;s running points total is stored against their user profile.</p><h3 id="what-points-unlock" tabindex="-1"><a class="header-anchor" href="#what-points-unlock"><span>What points unlock</span></a></h3><p>Configure via <strong>Auctions → Settings → Gamification → Rewards</strong>:</p><table><thead><tr><th>Threshold</th><th>Unlock</th></tr></thead><tbody><tr><td>100 points</td><td>Bronze tier — no fees on small auctions</td></tr><tr><td>500 points</td><td>Silver tier — 5% off buyer&#39;s premium</td></tr><tr><td>2,000 points</td><td>Gold tier — early access to flash auctions</td></tr><tr><td>10,000 points</td><td>VIP tier — concierge support</td></tr></tbody></table><p>Each tier triggers a notification when reached.</p><h2 id="badges" tabindex="-1"><a class="header-anchor" href="#badges"><span>Badges</span></a></h2><p>Predefined achievement badges:</p><table><thead><tr><th>Badge</th><th>Trigger</th></tr></thead><tbody><tr><td>🏁 First Bid</td><td>First bid placed</td></tr><tr><td>🏆 First Win</td><td>First auction won</td></tr><tr><td>💰 Big Spender</td><td>$1,000+ in winning bids</td></tr><tr><td>👁️ Hawk Eye</td><td>50+ watchlist additions</td></tr><tr><td>📋 Reviewer</td><td>10 reviews left</td></tr><tr><td>🔥 Hot Streak</td><td>5 consecutive wins</td></tr><tr><td>🎯 Sharpshooter</td><td>3 wins at exactly the reserve</td></tr><tr><td>🌎 Globetrotter</td><td>Bid on auctions in 5+ countries</td></tr><tr><td>🎁 Generous Donor</td><td>$500+ in <a href="/auction-types.html#charity" target="_blank" rel="noopener noreferrer">charity auctions</a></td></tr></tbody></table><p>Badges display on user profile, leaderboard, and bid form (next to their name).</p><h2 id="leaderboard" tabindex="-1"><a class="header-anchor" href="#leaderboard"><span>Leaderboard</span></a></h2><p>Public ranking page at <code>/leaderboard/</code> (template: <code>templates/leaderboard.php</code>).</p><table><thead><tr><th>Setting</th><th>Default</th></tr></thead><tbody><tr><td><code>wkafw_leaderboard_reset</code></td><td><code>never</code> (lifetime)</td></tr><tr><td>Leaderboard size</td><td>100</td></tr></tbody></table><p>Reset frequencies:</p><table><thead><tr><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td><code>never</code></td><td>Lifetime leaderboard</td></tr><tr><td><code>daily</code></td><td>Resets midnight UTC</td></tr><tr><td><code>weekly</code></td><td>Resets Sunday midnight UTC</td></tr><tr><td><code>monthly</code></td><td>Resets first of the month</td></tr></tbody></table><p>Customers can opt out of public visibility (&quot;private mode&quot;) in their account settings.</p><h2 id="achievements" tabindex="-1"><a class="header-anchor" href="#achievements"><span>Achievements</span></a></h2><p>Multi-step quests with progress UI:</p><table><thead><tr><th>Achievement</th><th>Steps</th></tr></thead><tbody><tr><td><strong>Auction Apprentice</strong></td><td>Place 1 bid → Win 1 auction → Leave 1 review</td></tr><tr><td><strong>Connoisseur</strong></td><td>Win 5 auctions in 3 different categories</td></tr><tr><td><strong>Charity Champion</strong></td><td>Donate $1,000+ across charity auctions</td></tr><tr><td><strong>Gold Rush</strong></td><td>Reach 10,000 lifetime points</td></tr><tr><td><strong>Watch Master</strong></td><td>Watch 100 auctions</td></tr></tbody></table><p>Render via the <strong>Achievements</strong> widget / block (<a href="/builders.html" target="_blank" rel="noopener noreferrer">Builders</a>).</p><h2 id="confetti-celebrations" tabindex="-1"><a class="header-anchor" href="#confetti-celebrations"><span>Confetti &amp; celebrations</span></a></h2><p>Hitting a milestone triggers visual celebration:</p><ul><li>Badge earned → modal with badge display + share button</li><li>Tier reached → push notification + email</li><li>Achievement complete → modal + achievement art</li></ul><p>Configurable via <code>wkafw_celebrations_enabled</code>.</p><h2 id="auction-of-the-day-flash-bonuses" tabindex="-1"><a class="header-anchor" href="#auction-of-the-day-flash-bonuses"><span>Auction of the Day &amp; flash bonuses</span></a></h2><p>Bidding on the <a href="/smart-features.html#auction-of-the-day" target="_blank" rel="noopener noreferrer">Auction of the Day</a> or a <a href="/smart-features.html#flash-auctions" target="_blank" rel="noopener noreferrer">flash auction</a> earns 2× points (configurable multiplier).</p><h2 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h2><p><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports → Gamification</a>:</p><ul><li>Total points awarded (currency-equivalent value)</li><li>Badges distributed</li><li>Leaderboard top users</li><li>Tier distribution</li><li>Achievement completion rate</li></ul><h2 id="anti-abuse" tabindex="-1"><a class="header-anchor" href="#anti-abuse"><span>Anti-abuse</span></a></h2><p>Points / badges can be gamed (e.g., placing trivial bids to farm points). Defenses:</p><ul><li>Bid amount minimum for points (<code>wkafw_min_bid_amount_for_points</code>)</li><li>Daily points cap per user</li><li>Points awarded only on <strong>valid</strong> bids (not retracted)</li><li>Suspicious patterns flagged by <a href="/admin-fraud.html" target="_blank" rel="noopener noreferrer">Fraud Detection</a></li></ul><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;Can I disable points entirely?&quot;</strong></p><p>Yes — set all <code>wkafw_points_per_*</code> to 0. The system still tracks them as 0; remove the leaderboard / achievements widgets to fully hide.</p><p><strong>&quot;How do I award points manually?&quot;</strong></p><p><strong>&quot;Do points expire?&quot;</strong></p><p>By default no. Set <code>wkafw_points_expiry_days</code> to enable annual / quarterly expiry.</p>',44)])])}]]),o=JSON.parse('{"path":"/gamification.html","title":"Gamification","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Components","slug":"components","link":"#components","children":[]},{"level":2,"title":"Points","slug":"points","link":"#points","children":[{"level":3,"title":"What points unlock","slug":"what-points-unlock","link":"#what-points-unlock","children":[]}]},{"level":2,"title":"Badges","slug":"badges","link":"#badges","children":[]},{"level":2,"title":"Leaderboard","slug":"leaderboard","link":"#leaderboard","children":[]},{"level":2,"title":"Achievements","slug":"achievements","link":"#achievements","children":[]},{"level":2,"title":"Confetti & celebrations","slug":"confetti-celebrations","link":"#confetti-celebrations","children":[]},{"level":2,"title":"Auction of the Day & flash bonuses","slug":"auction-of-the-day-flash-bonuses","link":"#auction-of-the-day-flash-bonuses","children":[]},{"level":2,"title":"Reporting","slug":"reporting","link":"#reporting","children":[]},{"level":2,"title":"Anti-abuse","slug":"anti-abuse","link":"#anti-abuse","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"gamification.md"}')}}]);